import React from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/one.png";
import img2 from "./images/two.png";
import img3 from "./images/three.png";
import img4 from "./images/four.png";
import img5 from "./images/five.png";
import img6 from "./images/six.png";
import img7 from "./images/seven.png";
import img8 from "./images/eight.png";
import img9 from "./images/nine.png";
import img10 from "./images/ten.png";
import "./App.css";

function App() {
  function handleMouseOver(e) {
    const tooltip = e.target.nextSibling;
    tooltip.style.opacity = 1;
  }

  function handleMouseOut(e) {
    const tooltip = e.target.nextSibling;
    tooltip.style.opacity = 0;
  }

  return (
    <div className="App">
      <div className="title">
        <h1>Our Technology Partner</h1>
      </div>

      <div>
        <Marquee direction="right" speed={100} delay={5}>
          <div className="image_wrapper">
            <img
              src={img1}
              alt=""
              onMouseOver={handleMouseOver}
              onMouseOut={handleMouseOut}
              style={{
                width: "100px",
                height: "100px",
                border: "1px solid black",
              }}
            />
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img2} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 2</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img3} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 3</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img4} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 4</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img5} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 5</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img6} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 6</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img7} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 7</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img8} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 8</div>
          </div>

          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img9} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 9</div>
          </div>
          <div
            className="image_wrapper"
            onMouseEnter={handleMouseEnter}
            onMouseLeave={handleMouseLeave}
          >
            <img src={img10} alt="" width="240" height="120" />
            <div className="tooltip">Tooltip text for image 10</div>
          </div>
        </Marquee>
      </div>
    </div>
  );
}

export default App;
